SELECT DISTINCT sku
FROM products
ORDER BY sku;

SELECT quantity_in_stock
FROM inventory
WHERE sku = '0';

SELECT SUM(quantity_in_stock) AS total_in_stock
FROM inventory
WHERE sku = '1';

SELECT description
FROM products
WHERE sku = '0';

SELECT COUNT(*) 
FROM products 
WHERE category_id = (SELECT category_id FROM categories WHERE category_name = 'Handles');
